import numpy as np

class McElieceKeyGen:
    def __init__(self, n: int, k: int, t: int):
        self.n = n
        self.k = k
        self.t = t

    def random_invertible(self, size: int) -> np.ndarray:
        while True:
            M = np.random.randint(0, 2, (size, size))
            try:
                aug = np.hstack([M, np.eye(size, dtype=int)]) % 2
                for col in range(size):
                    pivot = None
                    for row in range(col, size):
                        if aug[row, col] == 1:
                            pivot = row
                            break
                    if pivot is None:
                        raise ValueError()
                    aug[[col, pivot]] = aug[[pivot, col]]
                    for row in range(size):
                        if row != col and aug[row, col] == 1:
                            aug[row] = (aug[row] + aug[col]) % 2
                return M
            except:
                continue

    def random_permutation_matrix(self, n: int) -> np.ndarray:
        perm = np.random.permutation(n)
        return np.eye(n, dtype=int)[perm]

    def generate(self, G_secret: np.ndarray) -> tuple:
        S = self.random_invertible(self.k)
        P = self.random_permutation_matrix(self.n)
        G_public = (S @ G_secret @ P) % 2
        return G_public, (S, G_secret, P)

