class McElieceSizes:
    @staticmethod
    def public_key_bits(n: int, k: int) -> int:
        return k * n

    @staticmethod
    def ciphertext_bits(n: int) -> int:
        return n

    @staticmethod
    def compare_parameters(params: list) -> dict:
        results = {}
        for name, n, k, t in params:
            pk_kb = (k * n) // 8 // 1024
            ct_bytes = n // 8
            results[name] = {'pk_kb': pk_kb, 'ct_bytes': ct_bytes, 't': t}
        return results

