import math

class SecurityEstimator:
    @staticmethod
    def isd_work_factor(n: int, k: int, t: int) -> float:
        # Simplified Prange estimate: log2(C(n,t) * (k/n)^t)
        # More accurate: use BJMM complexity formulas
        try:
            log_work = t * math.log2(n / t) - t * math.log2(k / n)
            return log_work
        except:
            return 0

    @staticmethod
    def recommend_parameters(target_security: int) -> dict:
        presets = {
            128: {'n': 3488, 'k': 2720, 't': 64, 'pk_kb': 261},
            192: {'n': 4608, 'k': 3360, 't': 96, 'pk_kb': 524},
            256: {'n': 6688, 'k': 5024, 't': 128, 'pk_kb': 1044}
        }
        if target_security <= 128:
            return presets[128]
        elif target_security <= 192:
            return presets[192]
        return presets[256]
